function Avatar({ nome, fotos, size=28, fontSize=11 }) {
  const foto = fotos && fotos[nome];
  return (
    <div style={{
      width:size+'px', height:size+'px', borderRadius:'50%',
      background:'#0e1e12', border:'1.5px solid #c9a84c',
      overflow:'hidden', display:'flex', alignItems:'center',
      justifyContent:'center', flexShrink:0
    }}>
      {foto
        ? <img src={foto} alt={nome} style={{width:'100%',height:'100%',objectFit:'cover'}}/>
        : <span style={{color:'#c9a84c',fontSize:fontSize+'px',fontWeight:'500'}}>{nome?nome.charAt(0):''}</span>
      }
    </div>
  );
}


