function App() {
  const [tela, setTela] = useState('home');
  const [, setUsuario] = useState(null);
  const [jogadorPerfil, setJogadorPerfil] = useState('');
  const [splash, setSplash] = useState(true);
  const [darkMode, setDarkMode] = useState(() => localStorage.getItem('darkMode') === 'true');
  const [fotosJogadores, setFotosJogadores] = useState({});

  useEffect(() => {
    const p = new URLSearchParams(window.location.search);
    if (p.get('jogo') || p.get('j')) {
      setSplash(false);
      setTela('confirmar');
      return;
    }
    if (p.get('mvp')) {
      setSplash(false);
      setTela('votarmvp');
      return;
    }
    const timer = setTimeout(() => setSplash(false), 2200);

    const carregarFotos = () => {
      getDocs(collection(db,'perfis')).then(snap => {
        const fotos = {};
        snap.docs.forEach(d => {
          const data = d.data();
          if (data.nome && data.fotos && data.fotos.length > 0) {
            fotos[data.nome] = data.fotos[0];
          }
        });
        setFotosJogadores(fotos);
      });
    };

    carregarFotos();

    // Auto-refresh a cada 30 segundos
    const intervalo = setInterval(() => {
      carregarFotos();
    }, 30000);

    // Detectar nova versao do service worker
    if ('serviceWorker' in navigator) {
      navigator.serviceWorker.addEventListener('controllerchange', () => {
        window.location.reload();
      });
    }

    // Atualizar quando voltar para o app (usuario sai e volta)
    const handleVisibilidade = () => {
      if (document.visibilityState === 'visible') {
        carregarFotos();
      }
    };
    document.addEventListener('visibilitychange', handleVisibilidade);

    return () => {
      clearTimeout(timer);
      clearInterval(intervalo);
      document.removeEventListener('visibilitychange', handleVisibilidade);
    };
  }, []);

  useEffect(() => {
    localStorage.setItem('darkMode', darkMode);
    document.body.classList.toggle('dark', darkMode);
  }, [darkMode]);

  if (splash) return <Splash />;

  return (
    <div className="app">
      {tela === 'home'      && <Home setTela={setTela} darkMode={darkMode} setDarkMode={setDarkMode} fotosJogadores={fotosJogadores} />}
      {tela === 'jogador'   && <AreaJogador setTela={setTela} setJogadorPerfil={setJogadorPerfil} fotosJogadores={fotosJogadores} />}
      {tela === 'agenda'    && <Agenda setTela={setTela} setJogadorPerfil={setJogadorPerfil} fotosJogadores={fotosJogadores} />}
      {tela === 'instalar'  && <Instalar setTela={setTela} />}
      {tela === 'login'     && <Login setTela={setTela} setUsuario={setUsuario} />}
      {tela === 'painel'    && <Painel setTela={setTela} setUsuario={setUsuario} fotosJogadores={fotosJogadores} />}
      {tela === 'confirmar' && <Confirmar />}
      {tela === 'votarmvp'  && <VotarMVP setTela={setTela} />}
      {tela === 'perfil'    && <Perfil setTela={setTela} jogadorNome={jogadorPerfil} />}
      {tela === 'desafio'   && <Desafio setTela={setTela} />}
    </div>
  );
}

