                          <button onClick={e=>{e.stopPropagation();setJogadorPerfil(jog);setTela('perfil');}} style={{background:'#E6F1FB',border:'none',borderRadius:'6px',padding:'3px 8px',fontSize:'11px',color:'#0C447C',cursor:'pointer'}}>Perfil</button>
