const registrarTokenFCM = async (nomeJogador) => {
  try {
    if (!('Notification' in window)) return;
    const permission = await Notification.requestPermission();
    if (permission !== 'granted') return;
    // Importar FCM dinamicamente
    const { getMessaging, getToken } = await import('firebase/messaging');
    const messaging = getMessaging();
    const VAPID_KEY = 'BEl62iUYgUivxIkv69yViEuiBIa-Ib9-SkvMeAtA3LFgDkBWseIkuokgq5dOesg_5W_tCRF7q5q1uVlw';
    const token = await getToken(messaging, { vapidKey: VAPID_KEY });
    if (token && nomeJogador) {
      await addDoc(collection(db, 'tokens'), { token, nome: nomeJogador, atualizadoEm: new Date().toISOString() });
    }
  } catch(e) { console.log('FCM nao disponivel:', e); }
};

function AreaJogador({ setTela, setJogadorPerfil, fotosJogadores }) {
  const [nome, setNome] = useState(localStorage.getItem('meu_nome')||'');
  const [buscou, setBuscou] = useState(!!localStorage.getItem('meu_nome'));
  const [jogos, setJogos] = useState([]);
  const [load, setLoad] = useState(false);
  const [aba, setAba] = useState('proximos');

  const todosNomes = [
    'A20','Jean (Mortadela)','Raubustt (Arroz)','Gabriel (Dodoi)','Dennis (Samurai)',
    'Keti','Karla','Suelen','Elisa','Vanessa','Karol',
    'Mcdvr','Alice','Antonia','Fabi','Pardal','Kurt'
  ];

  const buscar = async (n) => {
    if (!n) return;
    setLoad(true);
    localStorage.setItem('meu_nome', n);
    setBuscou(true);
    registrarTokenFCM(n);
    await recarregar(n);
  };

  const recarregar = async (n) => {
    const nomeBusca = n || nome;
    if (!nomeBusca) return;
    setLoad(true);
    const snap = await getDocs(collection(db,'jogos'));
    const lista = snap.docs.map(d=>({id:d.id,...d.data()}))
      .filter(j => !j.excluido && (j.jogadores||[]).includes(nomeBusca))
      .sort((a,b) => new Date(a.data)-new Date(b.data));
    setJogos(lista);
    setLoad(false);
  };

  // Auto-refresh quando voltar para o app
  useEffect(()=>{
    if (!buscou || !nome) return;
    const handleVis = () => { if (document.visibilityState==='visible') recarregar(nome); };
    document.addEventListener('visibilitychange', handleVis);
    const intervalo = setInterval(()=>recarregar(nome), 30000);
    return () => { document.removeEventListener('visibilitychange', handleVis); clearInterval(intervalo); };
  },[buscou, nome]);

  const hoje = new Date().toISOString().split('T')[0];
  const proximos = jogos.filter(j=>j.data>=hoje);
  const anteriores = jogos.filter(j=>j.data<hoje);
  const totalJogos = jogos.length;
  const totalConfirmados = jogos.filter(j=>j.confirmacoes&&j.confirmacoes[nome]==='sim').length;
  const aprov = totalJogos>0?Math.round((totalConfirmados/totalJogos)*100):0;
  // Vitorias dos jogos que o jogador participou
  const jogosComPlacar = jogos.filter(j=>j.placar&&j.confirmacoes&&j.confirmacoes[nome]==='sim');
  const vitorias = jogosComPlacar.filter(j=>j.placar.resultado==='vitoria').length;

  const bgC = s=>s==='sim'?'#EAF3DE':s==='nao'?'#FCEBEB':'#FAEEDA';
  const corC = s=>s==='sim'?'#27500A':s==='nao'?'#791F1F':'#633806';
  const txtC = s=>s==='sim'?'Confirmado':s==='nao'?'Nao foi':'Pendente';

  return (
    <div style={{background:'#f5f5f5',minHeight:'100vh'}}>
      <div style={{background:'#0e1e12',padding:'14px 16px',display:'flex',alignItems:'center',gap:'10px'}}>
        <BtnVoltar onClick={()=>setTela('home')}/>
        <div>
          <h2 style={{color:'#c9a84c',fontSize:'15px',fontWeight:'500'}}>Minha Area</h2>
          <p style={{color:'rgba(201,168,76,0.5)',fontSize:'11px'}}>Volei Tche</p>
        </div>
      </div>

      {!buscou ? (
        <div style={{padding:'24px 16px'}}>
          <div style={{background:'#fff',borderRadius:'16px',padding:'20px',border:'0.5px solid #ddd',textAlign:'center'}}>
            <div style={{fontSize:'40px',marginBottom:'12px'}}>🏐</div>
            <div style={{fontSize:'16px',fontWeight:'500',color:'#333',marginBottom:'6px'}}>Minha Area</div>
            <div style={{fontSize:'13px',color:'#666',marginBottom:'16px'}}>Selecione seu nome para ver seus jogos e confirmar presenca</div>
            <div style={{background:'#f9f9f9',borderRadius:'12px',padding:'14px',marginBottom:'16px',textAlign:'left'}}>
              <div style={{fontSize:'12px',fontWeight:'500',color:'#333',marginBottom:'10px'}}>Como usar:</div>
              {[
                {n:'1',t:'Selecione seu nome','d':'Escolha seu nome na lista abaixo'},
                {n:'2',t:'Veja seus jogos','d':'Proximos jogos e historico aparecem automaticamente'},
                {n:'3',t:'Confirme presenca','d':'Toque em "Bora la!" ou "Nao poderei ir" em cada jogo'},
                {n:'4',t:'Acesse seu perfil','d':'Adicione foto, WhatsApp e posicoes favoritas'},
              ].map((p,i)=>(
                <div key={i} style={{display:'flex',gap:'10px',alignItems:'flex-start',marginBottom:'8px'}}>
                  <div style={{width:'24px',height:'24px',borderRadius:'50%',background:'#0e1e12',color:'#c9a84c',display:'flex',alignItems:'center',justifyContent:'center',fontSize:'12px',fontWeight:'500',flexShrink:0}}>{p.n}</div>
                  <div>
                    <div style={{fontSize:'13px',fontWeight:'500',color:'#333'}}>{p.t}</div>
                    <div style={{fontSize:'12px',color:'#666'}}>{p.d}</div>
                  </div>
                </div>
              ))}
            </div>
            <select value={nome} onChange={e=>setNome(e.target.value)} style={{width:'100%',padding:'13px 14px',border:'2px solid #ddd',borderRadius:'12px',fontSize:'16px',background:'#fff',color:'#333',marginBottom:'12px'}}>
              <option value="">Selecione seu nome...</option>
              {todosNomes.map(n=><option key={n} value={n}>{n}</option>)}
            </select>
            <button onClick={()=>buscar(nome)} disabled={!nome} style={{width:'100%',padding:'13px',background:'#0e1e12',color:'#c9a84c',border:'none',borderRadius:'12px',fontSize:'15px',fontWeight:'500',cursor:'pointer',opacity:nome?1:0.4}}>
              Entrar
            </button>
            {nome && (
              <button onClick={()=>{localStorage.setItem('meu_nome',nome);setJogadorPerfil(nome);setTela('perfil');}} style={{width:'100%',padding:'11px',background:'transparent',color:'#0e1e12',border:'1px solid #c9a84c',borderRadius:'12px',fontSize:'14px',cursor:'pointer',marginTop:'8px',fontWeight:'400'}}>
                Acessar perfil de {nome}
              </button>
            )}
          </div>
        </div>
      ) : (
        <div>
          <div style={{background:'#0e1e12',padding:'12px 16px',display:'flex',alignItems:'center',gap:'10px',borderTop:'0.5px solid rgba(201,168,76,0.1)'}}>
            <div style={{width:'40px',height:'40px',borderRadius:'50%',border:'2px solid #c9a84c',overflow:'hidden',display:'flex',alignItems:'center',justifyContent:'center',background:'#0e1e12',flexShrink:0}}>
              {fotosJogadores[nome]
                ?<img src={fotosJogadores[nome]} alt={nome} style={{width:'100%',height:'100%',objectFit:'cover'}}/>
                :<span style={{color:'#c9a84c',fontSize:'18px',fontWeight:'500'}}>{nome.charAt(0)}</span>
              }
            </div>
            <div style={{flex:1}}>
              <div style={{color:'#c9a84c',fontSize:'15px',fontWeight:'500'}}>{nome}</div>
              <div style={{color:'rgba(201,168,76,0.5)',fontSize:'11px'}}>{proximos.length} proximos jogos</div>
            </div>
            <div style={{display:'flex',gap:'6px'}}>
              <button onClick={()=>recarregar(nome)} style={{background:'transparent',border:'1px solid rgba(201,168,76,0.3)',color:'rgba(201,168,76,0.6)',padding:'4px 10px',borderRadius:'8px',fontSize:'11px',cursor:'pointer'}}>
                Atualizar
              </button>
              <button onClick={()=>{setNome('');setBuscou(false);localStorage.removeItem('meu_nome');}} style={{background:'transparent',border:'1px solid rgba(201,168,76,0.3)',color:'rgba(201,168,76,0.6)',padding:'4px 10px',borderRadius:'8px',fontSize:'11px',cursor:'pointer'}}>
                Trocar
              </button>
            </div>
          </div>

          <div style={{padding:'0 16px 8px'}}>
            <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:'6px'}}>
              <div style={{background:'#fff',borderRadius:'12px',padding:'10px 6px',textAlign:'center',border:'0.5px solid #ddd'}}>
                <div style={{fontSize:'22px',fontWeight:'500',color:'#0e1e12'}}>{totalJogos}</div>
                <div style={{fontSize:'10px',color:'#666',marginTop:'2px'}}>Jogos</div>
              </div>
              <div style={{background:'#fff',borderRadius:'12px',padding:'10px 6px',textAlign:'center',border:'0.5px solid #ddd'}}>
                <div style={{fontSize:'22px',fontWeight:'500',color:'#27500A'}}>{totalConfirmados}</div>
                <div style={{fontSize:'10px',color:'#666',marginTop:'2px'}}>Presencas</div>
              </div>
              <div style={{background:'#fff',borderRadius:'12px',padding:'10px 6px',textAlign:'center',border:'0.5px solid #ddd'}}>
                <div style={{fontSize:'22px',fontWeight:'500',color:'#27500A'}}>{vitorias}</div>
                <div style={{fontSize:'10px',color:'#666',marginTop:'2px'}}>Vitorias</div>
              </div>
              <div style={{background:'#fff',borderRadius:'12px',padding:'10px 6px',textAlign:'center',border:'0.5px solid #ddd'}}>
                <div style={{fontSize:'22px',fontWeight:'500',color:aprov>=70?'#27500A':aprov>=40?'#633806':'#791F1F'}}>{aprov}%</div>
                <div style={{fontSize:'10px',color:'#666',marginTop:'2px'}}>Aproveit.</div>
              </div>
            </div>
          </div>

          <div style={{display:'flex',background:'#0e1e12',margin:'0',padding:'0 8px',gap:'3px'}}>
            {['proximos','historico'].map(a=>(
              <div key={a} onClick={()=>setAba(a)} style={{flex:1,padding:'10px 4px',textAlign:'center',fontSize:'12px',color:aba===a?'#c9a84c':'rgba(201,168,76,0.4)',borderBottom:aba===a?'2px solid #c9a84c':'2px solid transparent',cursor:'pointer',fontWeight:aba===a?'500':'400'}}>
                {a==='proximos'?'Proximos Jogos':'Historico'}
              </div>
            ))}
          </div>

          {load && <div style={{textAlign:'center',padding:'30px',color:'#666'}}>Carregando...</div>}

          {!load && aba==='proximos' && (
            <div style={{padding:'14px'}}>
              {proximos.length===0 ? (
                <div style={{textAlign:'center',padding:'30px',color:'#666'}}>
                  <div style={{fontSize:'32px',marginBottom:'8px'}}>📅</div>
                  <div>Nenhum jogo agendado ainda</div>
                </div>
              ) : proximos.map(j=>{
                const resp = j.confirmacoes&&j.confirmacoes[nome];
                const idRef = j.idCurto||j.id;
                const linkSim = BASE_URL+'?j='+idRef+'&n='+encodeURIComponent(nome)+'&r=s';
                const linkNao = BASE_URL+'?j='+idRef+'&n='+encodeURIComponent(nome)+'&r=n';
                return (
                  <div key={j.id} style={{background:'#fff',borderRadius:'12px',padding:'14px',marginBottom:'10px',border:'0.5px solid #ddd'}}>
                    <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:'8px'}}>
                      <div>
                        <div style={{fontSize:'14px',fontWeight:'500',color:'#333'}}>{j.modalidade}</div>
                        <div style={{fontSize:'12px',color:'#666',marginTop:'2px'}}>{j.data} as {j.hora}</div>
                        <div style={{fontSize:'12px',color:'#666'}}>{j.local||'Local a confirmar'}</div>
                      </div>
                      <span style={{fontSize:'11px',padding:'3px 10px',borderRadius:'99px',fontWeight:'500',background:bgC(resp),color:corC(resp)}}>{txtC(resp)}</span>
                    </div>
                    {j.recado&&<div style={{fontSize:'12px',color:'#555',fontStyle:'italic',marginBottom:'10px',padding:'8px',background:'#f9f9f9',borderRadius:'8px'}}>"{j.recado}"</div>}
                    {!resp && (
                      <div style={{display:'flex',gap:'8px'}}>
                        <a href={linkSim} style={{flex:1,padding:'10px',background:'#1a3a1a',color:'#c9a84c',border:'none',borderRadius:'8px',fontSize:'13px',fontWeight:'500',cursor:'pointer',textAlign:'center',textDecoration:'none'}}>Bora la!</a>
                        <a href={linkNao} style={{flex:1,padding:'10px',background:'#fff',color:'#791F1F',border:'1px solid #E24B4A',borderRadius:'8px',fontSize:'13px',cursor:'pointer',textAlign:'center',textDecoration:'none'}}>Nao poderei ir</a>
                      </div>
                    )}
                    {resp && (
                      <div style={{display:'flex',gap:'8px'}}>
                        <a href={resp==='sim'?linkNao:linkSim} style={{width:'100%',padding:'9px',background:'#f5f5f5',color:'#666',border:'0.5px solid #ddd',borderRadius:'8px',fontSize:'12px',cursor:'pointer',textAlign:'center',textDecoration:'none'}}>
                          {resp==='sim'?'Mudar para Nao poderei ir':'Mudar para Bora la!'}
                        </a>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )}

          {!load && aba==='historico' && (
            <div style={{padding:'14px'}}>
              {anteriores.length===0 ? (
                <div style={{textAlign:'center',padding:'30px',color:'#666'}}>
                  <div style={{fontSize:'32px',marginBottom:'8px'}}>🏆</div>
                  <div>Nenhum jogo no historico ainda</div>
                </div>
              ) : [...anteriores].reverse().map(j=>{
                const resp = j.confirmacoes&&j.confirmacoes[nome];
                return (
                  <div key={j.id} style={{background:'#fff',borderRadius:'12px',padding:'14px',marginBottom:'10px',border:'0.5px solid #ddd',display:'flex',alignItems:'center',gap:'12px'}}>
                    <div style={{width:'36px',height:'36px',borderRadius:'50%',background:resp==='sim'?'#EAF3DE':resp==='nao'?'#FCEBEB':'#FAEEDA',display:'flex',alignItems:'center',justifyContent:'center',fontSize:'16px',flexShrink:0}}>
                      {resp==='sim'?'ok':resp==='nao'?'x':'?'}
                    </div>
                    <div style={{flex:1}}>
                      <div style={{fontSize:'13px',fontWeight:'500',color:'#333'}}>{j.modalidade}</div>
                      <div style={{fontSize:'11px',color:'#666'}}>{j.data} - {j.local||'Sem local'}</div>
                      {j.placar&&<div style={{fontSize:'11px',color:j.placar.resultado==='vitoria'?'#27500A':'#791F1F',marginTop:'2px',fontWeight:'500'}}>{j.placar.resultado==='vitoria'?'Vitoria':'Derrota'} {j.placar.nosVencemos}x{j.placar.elesVenceram} vs {j.placar.adversario}</div>}
                    </div>
                    <span style={{fontSize:'11px',padding:'2px 8px',borderRadius:'99px',background:bgC(resp),color:corC(resp)}}>{txtC(resp)}</span>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      )}
    </div>
  );
}


function VotarMVP({ setTela }) {
  const [jogo, setJogo] = useState(null);
  const [load, setLoad] = useState(true);
  const [mvpAtual, setMvpAtual] = useState('');
  const [votos, setVotos] = useState({});
  const [nomeVotante, setNomeVotante] = useState('');
  const [etapa, setEtapa] = useState('identificar'); // identificar, votar, obrigado

  useEffect(()=>{
    const p = new URLSearchParams(window.location.search);
    const jogoId = p.get('mvp');
    if (!jogoId) { setLoad(false); return; }
    getDocs(collection(db,'jogos')).then(snap=>{
      const found = snap.docs.find(d=>d.id===jogoId);
      if (found) {
        const data = {id:found.id,...found.data()};
        setJogo(data);
        setVotos(data.votosVmp||{});
        if (data.placar?.mvp) setMvpAtual(data.placar.mvp);
      }
      setLoad(false);
    });
  },[]);

  const votar = async (candidato) => {
    if (!nomeVotante) return;
    const novosVotos = {...votos, [nomeVotante]: candidato};
    setVotos(novosVotos);
    // Calcular MVP com mais votos
    const contagem = {};
    Object.values(novosVotos).forEach(v=>{ contagem[v]=(contagem[v]||0)+1; });
    const mvpEscolhido = Object.entries(contagem).sort((a,b)=>b[1]-a[1])[0]?.[0]||'';
    await updateDoc(doc(db,'jogos',jogo.id),{
      votosVmp: novosVotos,
      'placar.mvp': mvpEscolhido
    });
    setMvpAtual(mvpEscolhido);
    
    setEtapa('obrigado');
  };

  if (load) return (
    <div style={{minHeight:'100vh',background:'#0e1e12',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',gap:'16px'}}>
      <div style={{color:'#c9a84c',fontSize:'14px'}}>Carregando...</div>
    </div>
  );

  if (!jogo) return (
    <div style={{minHeight:'100vh',background:'#f5f5f5',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',padding:'20px',textAlign:'center',gap:'12px'}}>
      <div style={{fontSize:'40px'}}>🔗</div>
      <div style={{fontSize:'16px',fontWeight:'500',color:'#333'}}>Link invalido</div>
      <button onClick={()=>window.location.href=BASE_URL} style={{padding:'12px 24px',background:'#0e1e12',color:'#c9a84c',border:'none',borderRadius:'10px',fontSize:'14px',cursor:'pointer'}}>Ir para o app</button>
    </div>
  );

  const confirmados = (jogo.jogadores||[]).filter(j=>jogo.confirmacoes&&jogo.confirmacoes[j]==='sim');
  const contagem = {};
  Object.values(votos).forEach(v=>{ contagem[v]=(contagem[v]||0)+1; });
  const totalVotos = Object.keys(votos).length;

  return (
    <div style={{minHeight:'100vh',background:'#f5f5f5',overflowX:'hidden'}}>
      {/* Header dourado */}
      <div style={{background:'linear-gradient(135deg,#0e1e12,#1a3a1a)',padding:'20px 16px',textAlign:'center'}}>
        <div style={{fontSize:'40px',marginBottom:'8px'}}>🏆</div>
        <h2 style={{color:'#c9a84c',fontSize:'20px',fontWeight:'700',marginBottom:'4px'}}>Vote no MVP!</h2>
        <p style={{color:'rgba(201,168,76,0.6)',fontSize:'13px'}}>{jogo.modalidade} - {jogo.data}</p>
        <div style={{marginTop:'12px',background:'rgba(201,168,76,0.1)',borderRadius:'10px',padding:'8px 14px',display:'inline-block'}}>
          <span style={{color:'#c9a84c',fontSize:'13px'}}>{totalVotos} voto{totalVotos!==1?'s':''}</span>
        </div>
        {mvpAtual&&(
          <div style={{marginTop:'12px',background:'linear-gradient(135deg,#c9a84c,#f0d080)',borderRadius:'12px',padding:'10px 16px',display:'inline-flex',alignItems:'center',gap:'8px'}}>
            <span style={{fontSize:'20px'}}>🏆</span>
            <div style={{textAlign:'left'}}>
              <div style={{fontSize:'10px',fontWeight:'700',color:'#0e1e12',textTransform:'uppercase',letterSpacing:'1px'}}>MVP atual</div>
              <div style={{fontSize:'16px',fontWeight:'700',color:'#0e1e12'}}>{mvpAtual}</div>
            </div>
          </div>
        )}
      </div>

      <div style={{padding:'16px',boxSizing:'border-box',width:'100%'}}>

        {/* ETAPA: IDENTIFICAR */}
        {etapa==='identificar'&&(
          <div>
            <div style={{fontSize:'15px',fontWeight:'500',color:'#333',textAlign:'center',marginBottom:'12px'}}>Primeiro, qual e o seu nome?</div>
            <select value={nomeVotante} onChange={e=>setNomeVotante(e.target.value)} style={{width:'100%',padding:'13px 14px',border:'1.5px solid #ddd',borderRadius:'12px',fontSize:'16px',background:'#fff',color:'#333',marginBottom:'12px',boxSizing:'border-box'}}>
              <option value="">Selecione seu nome...</option>
              {confirmados.map((jog,i)=><option key={i} value={jog}>{jog}</option>)}
              <option value="Convidado">Convidado</option>
            </select>
            {nomeVotante&&(
              <button onClick={()=>{
                if (votos[nomeVotante]) { setEtapa('obrigado'); return; }
                setEtapa('votar');
              }} style={{width:'100%',padding:'14px',background:'#0e1e12',color:'#c9a84c',border:'none',borderRadius:'12px',fontSize:'15px',fontWeight:'500',cursor:'pointer',boxSizing:'border-box'}}>
                {votos[nomeVotante]?'Ver resultado':'Votar no MVP'}
              </button>
            )}
          </div>
        )}

        {/* ETAPA: VOTAR */}
        {etapa==='votar'&&(
          <div>
            <div style={{fontSize:'15px',fontWeight:'500',color:'#333',textAlign:'center',marginBottom:'4px'}}>Quem foi o melhor em campo?</div>
            <div style={{fontSize:'12px',color:'#999',textAlign:'center',marginBottom:'16px'}}>Nao pode votar em si mesmo</div>
            {confirmados.filter(j=>j!==nomeVotante).map((jog,i)=>{
              const qtd = contagem[jog]||0;
              return (
                <button key={i} onClick={()=>votar(jog)} style={{width:'100%',padding:'14px',background:'#fff',border:'1.5px solid #ddd',borderRadius:'12px',fontSize:'15px',color:'#333',cursor:'pointer',marginBottom:'8px',boxSizing:'border-box',display:'flex',alignItems:'center',gap:'10px',textAlign:'left'}}>
                  <div style={{width:'36px',height:'36px',borderRadius:'50%',background:'#0e1e12',color:'#c9a84c',display:'flex',alignItems:'center',justifyContent:'center',fontSize:'14px',fontWeight:'500',flexShrink:0}}>{jog.charAt(0)}</div>
                  <span style={{flex:1,fontWeight:'500'}}>{jog}</span>
                  <span style={{fontSize:'12px',color:'#999'}}>{qtd} voto{qtd!==1?'s':''}</span>
                </button>
              );
            })}
            <button onClick={()=>setEtapa('identificar')} style={{width:'100%',padding:'10px',background:'transparent',color:'#999',border:'none',fontSize:'12px',cursor:'pointer',marginTop:'4px'}}>Voltar</button>
          </div>
        )}

        {/* ETAPA: OBRIGADO */}
        {etapa==='obrigado'&&(
          <div style={{textAlign:'center'}}>
            <div style={{fontSize:'60px',marginBottom:'12px'}}>🙌</div>
            <h3 style={{fontSize:'20px',fontWeight:'700',color:'#333',marginBottom:'8px'}}>Obrigado pelo voto!</h3>
            <p style={{fontSize:'14px',color:'#666',marginBottom:'20px'}}>Voce votou em <strong>{votos[nomeVotante]}</strong></p>
            {mvpAtual&&(
              <div style={{background:'linear-gradient(135deg,#c9a84c,#f0d080)',borderRadius:'14px',padding:'16px',marginBottom:'16px',display:'flex',alignItems:'center',gap:'12px',justifyContent:'center'}}>
                <div style={{fontSize:'32px'}}>🏆</div>
                <div>
                  <div style={{fontSize:'11px',fontWeight:'700',color:'#0e1e12',textTransform:'uppercase',letterSpacing:'1px'}}>MVP do jogo</div>
                  <div style={{fontSize:'20px',fontWeight:'700',color:'#0e1e12'}}>{mvpAtual}</div>
                  <div style={{fontSize:'12px',color:'rgba(14,30,18,0.6)'}}>{contagem[mvpAtual]||0} voto{(contagem[mvpAtual]||0)!==1?'s':''}</div>
                </div>
              </div>
            )}
            <div style={{background:'#fff',borderRadius:'12px',padding:'14px',marginBottom:'12px',border:'0.5px solid #ddd'}}>
              <div style={{fontSize:'13px',fontWeight:'500',color:'#333',marginBottom:'10px'}}>Placar de votos</div>
              {Object.entries(contagem).sort((a,b)=>b[1]-a[1]).map(([jog,qtd],i)=>(
                <div key={i} style={{display:'flex',alignItems:'center',gap:'8px',marginBottom:'8px'}}>
                  <div style={{fontSize:'14px',width:'20px',textAlign:'center'}}>{i===0?'🥇':i===1?'🥈':i===2?'🥉':'  '}</div>
                  <span style={{flex:1,fontSize:'13px',color:'#333'}}>{jog}</span>
                  <div style={{flex:2,height:'6px',background:'#f0f0f0',borderRadius:'99px',overflow:'hidden'}}>
                    <div style={{height:'100%',background:i===0?'#c9a84c':'#ddd',borderRadius:'99px',width:totalVotos>0?(qtd/totalVotos*100)+'%':'0%'}}></div>
                  </div>
                  <span style={{fontSize:'12px',color:'#666',width:'20px',textAlign:'right'}}>{qtd}</span>
                </div>
              ))}
            </div>
            <button onClick={()=>window.location.href=BASE_URL} style={{width:'100%',padding:'13px',background:'#0e1e12',color:'#c9a84c',border:'none',borderRadius:'12px',fontSize:'14px',fontWeight:'500',cursor:'pointer',boxSizing:'border-box'}}>
              Voltar ao app
            </button>
          </div>
        )}
      </div>
    </div>
  );
}


function Desafio({ setTela }) {
  const [passo, setPasso] = useState(1);
  const [dados, setDados] = useState({time:'',contato:'',modalidade:'',data:'',horario:'',quadra:''});
  const [datasOcup, setDatasOcup] = useState([]);
  const [loadCal, setLoadCal] = useState(false);
  const [mes, setMes] = useState(new Date());
  const mods = ['Quarteto Masculino','Quarteto Feminino','Quarteto Misto','Dupla Masculina','Dupla Feminina','Resenha'];

  useEffect(()=>{
    if (passo===3) {
      setLoadCal(true);
      getDocs(collection(db,'jogos')).then(snap=>{
        setDatasOcup(snap.docs.map(d=>d.data().data).filter(Boolean));
        setLoadCal(false);
      });
    }
  },[passo]);

  const enviar = async () => {
    try {
      await addDoc(collection(db,'desafios'),{...dados,status:'pendente',criadoEm:new Date().toISOString()});
      const coord = isFem(dados.modalidade)?COORD_FEM:COORD_MASC;
      const msg = 'Novo desafio recebido!\nTime: '+dados.time+'\nModalidade: '+dados.modalidade+'\nData: '+dados.data+(dados.horario?'\nHorario: '+dados.horario:'')+(dados.quadra?'\nQuadra: '+dados.quadra:'')+'\nContato: '+dados.contato;
      wa(coord, msg);
      setPasso(4);
    } catch(e){alert('Erro ao enviar.');}
  };

  const diasMes = new Date(mes.getFullYear(),mes.getMonth()+1,0).getDate();
  const primDia = new Date(mes.getFullYear(),mes.getMonth(),1).getDay();
  const nomeMes = mes.toLocaleString('pt-BR',{month:'long',year:'numeric'});
  const hoje = new Date(); hoje.setHours(0,0,0,0);
  const ds = (dia) => mes.getFullYear()+'-'+String(mes.getMonth()+1).padStart(2,'0')+'-'+String(dia).padStart(2,'0');
  const diasSemana = ['domingo','segunda','terca','quarta','quinta','sexta','sabado'];
  const datasFixasLocal = JSON.parse(localStorage.getItem('datas_fixas')||'[]');
  const isDiaFixo = (dia) => {
    const d = new Date(ds(dia)+'T12:00:00');
    const nomeDia = diasSemana[d.getDay()];
    return datasFixasLocal.some(df => df.diaSemana === nomeDia);
  };

  return (
    <div className="desafio">
      <div style={{background:'#0e1e12',padding:'12px 14px',width:'100%',boxSizing:'border-box'}}>
        <div style={{display:'flex',alignItems:'center',gap:'10px',marginBottom:'8px'}}>
          <BtnVoltar onClick={()=>passo===1?setTela('home'):setPasso(passo-1)}/>
          <div>
            <h2 style={{color:'#c9a84c',fontSize:'15px',fontWeight:'500'}}>Desafiar o Volei Tche</h2>
            <p style={{color:'rgba(201,168,76,0.5)',fontSize:'11px'}}>Passo {passo} de 3</p>
          </div>
        </div>
        <div style={{background:'rgba(255,255,255,0.1)',borderRadius:'99px',height:'4px',width:'100%'}}>
          <div style={{background:'#c9a84c',borderRadius:'99px',height:'4px',width:((passo/3)*100)+'%',transition:'width 0.3s'}}></div>
        </div>
      </div>
      <div style={{padding:'16px',width:'100%',boxSizing:'border-box'}}>
        {passo===1&&(
          <div>
            <h3 style={{fontSize:'18px',fontWeight:'600',color:'#333',marginBottom:'16px'}}>Seus dados</h3>
            {[
              {ph:'Nome do seu time',val:dados.time,key:'time'},
              {ph:'WhatsApp com DDD (Ex: 51999990001)',val:dados.contato,key:'contato'},
              {ph:'Horario desejado (Ex: 19h00)',val:dados.horario,key:'horario'},
              {ph:'Quadra (Ex: Quadra A)',val:dados.quadra,key:'quadra'},
            ].map((f,i)=>(
              <input key={i} placeholder={f.ph} value={f.val} onChange={e=>setDados({...dados,[f.key]:e.target.value})}
                style={{width:'100%',padding:'14px',border:'1.5px solid #ddd',borderRadius:'12px',fontSize:'15px',background:'#fff',color:'#333',marginBottom:'10px',boxSizing:'border-box',display:'block'}}
              />
            ))}
            <button onClick={()=>{
              if(!dados.time||!dados.contato) return alert('Preencha nome do time e WhatsApp!');
              setPasso(2);
            }} style={{width:'100%',padding:'15px',background:'#0e1e12',color:'#c9a84c',border:'none',borderRadius:'12px',fontSize:'16px',fontWeight:'600',cursor:'pointer',boxSizing:'border-box'}}>
              Proximo →
            </button>
          </div>
        )}
        {passo===2&&(
          <div>
            <h3 style={{fontSize:'18px',fontWeight:'600',color:'#333',marginBottom:'16px'}}>Modalidade</h3>
            {mods.map(m=>(
              <div key={m} onClick={()=>setDados({...dados,modalidade:m})}
                style={{width:'100%',padding:'14px',background:dados.modalidade===m?'#1a3a1a':'#fff',border:dados.modalidade===m?'2px solid #4caf50':'1.5px solid #ddd',borderRadius:'12px',fontSize:'15px',color:dados.modalidade===m?'#c9a84c':'#333',cursor:'pointer',marginBottom:'8px',boxSizing:'border-box',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
                <span>{m}</span>{dados.modalidade===m&&<span style={{color:'#c9a84c',fontWeight:'700'}}>✓</span>}
              </div>
            ))}
            <button onClick={()=>{
              if(!dados.modalidade) return alert('Selecione uma modalidade!');
              setPasso(3);
            }} style={{width:'100%',padding:'15px',background:'#0e1e12',color:'#c9a84c',border:'none',borderRadius:'12px',fontSize:'16px',fontWeight:'600',cursor:'pointer',boxSizing:'border-box',marginTop:'8px'}}>
              Proximo →
            </button>
          </div>
        )}
        {passo===3&&(
          <div>
            <h3>Escolha uma data disponivel</h3>
            {loadCal?<div style={{textAlign:'center',padding:'20px',color:'#666'}}>Carregando...</div>:(
              <div className="calendario-desafio">
                <div className="cal-nav">
                  <button className="cal-nav-btn" onClick={()=>{const d=new Date(mes);d.setMonth(d.getMonth()-1);setMes(d);}}>&lt;</button>
                  <div className="cal-mes-nome">{nomeMes.charAt(0).toUpperCase()+nomeMes.slice(1)}</div>
                  <button className="cal-nav-btn" onClick={()=>{const d=new Date(mes);d.setMonth(d.getMonth()+1);setMes(d);}}>&gt;</button>
                </div>
                <div className="cal-grid">
                  {['D','S','T','Q','Q','S','S'].map((d,i)=><div key={i} className="cal-header-dia">{d}</div>)}
                  {Array.from({length:primDia}).map((_,i)=><div key={'e'+i}></div>)}
                  {Array.from({length:diasMes}).map((_,i)=>{
                    const dia=i+1, dStr=ds(dia);
                    const ocupado=datasOcup.includes(dStr)||isDiaFixo(dia);
                    const passado=new Date(dStr+'T12:00:00')<hoje;
                    const sel=dados.data===dStr;
                    const bloq=ocupado||passado;
                    return <div key={dia} className={'cal-dia-desafio'+(sel?' cal-selecionado':'')+(bloq?' cal-bloqueado':' cal-disponivel')} onClick={()=>!bloq&&setDados({...dados,data:dStr})}>{dia}{ocupado&&<div className="cal-ponto-ocupado"></div>}</div>;
                  })}
                </div>
                <div className="cal-legenda">
                  <div className="cal-leg-item"><div className="cal-leg-dot" style={{background:'#EAF3DE',border:'1px solid #4caf50'}}></div> Disponivel</div>
                  <div className="cal-leg-item"><div className="cal-leg-dot" style={{background:'#f5f5f5'}}></div> Ocupado</div>
                  <div className="cal-leg-item"><div className="cal-leg-dot" style={{background:'#0e1e12'}}></div> Selecionado</div>
                </div>
                {dados.data&&<div className="cal-data-selecionada">Selecionado: {new Date(dados.data+'T12:00:00').toLocaleDateString('pt-BR',{weekday:'long',day:'numeric',month:'long'})}</div>}
              </div>
            )}
            <button className="btn-next" onClick={enviar} disabled={!dados.data}>Enviar desafio!</button>
          </div>
        )}
        {passo===4&&(
          <div style={{textAlign:'center',padding:'20px'}}>
            <div style={{fontSize:'50px',marginBottom:'12px'}}></div>
            <h3 style={{color:'#0e1e12',marginBottom:'8px'}}>Desafio enviado!</h3>
            <p style={{color:'#666',marginBottom:'20px'}}>O coordenador foi notificado pelo WhatsApp!</p>
            <div style={{background:'#f5f5f5',borderRadius:'10px',padding:'14px',textAlign:'left'}}>
              <p><strong>Time:</strong> {dados.time}</p>
              <p><strong>Modalidade:</strong> {dados.modalidade}</p>
              <p><strong>Data:</strong> {dados.data}</p>
              <p><strong>Horario:</strong> {dados.horario||'A combinar'}</p>
              <p><strong>Quadra:</strong> {dados.quadra||'A combinar'}</p>
              <p><strong>Contato:</strong> {dados.contato}</p>
            </div>
            <button className="btn-next" style={{marginTop:'16px'}} onClick={()=>setTela('home')}>Voltar ao inicio</button>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
